const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api/v1';

export async function fetchDashboardData() {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}/dashboard`, {
        headers: {
            'Authorization': `Bearer ${token}`
        }
    });
    if (!response.ok) throw new Error('Failed to fetch dashboard data');
    return response.json();
}

export async function fetchRecentActivity() {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}/dashboard/activity`, {
        headers: {
            "Authorization": `Bearer ${token}`,
        },
    })
    if (!response.ok) throw new Error("Failed to fetch activity")
    return response.json()
}

export async function fetchGaps() {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}/dashboard/gaps`, {
        headers: {
            "Authorization": `Bearer ${token}`,
        },
    })
    if (!response.ok) throw new Error("Failed to fetch gaps")
    return response.json()
}

export async function uploadCSV(file: File) {
    const token = localStorage.getItem('token');
    const formData = new FormData();
    formData.append('file', file);

    const response = await fetch(`${API_URL}/import/csv`, {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${token}`
        },
        body: formData
    });
    if (!response.ok) throw new Error('Failed to upload CSV');
    return response.json();
}

export async function getImportStatus(importId: string) {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}/import/csv/${importId}`, {
        headers: {
            'Authorization': `Bearer ${token}`
        }
    });
    if (!response.ok) throw new Error('Failed to fetch import status');
    return response.json();
}

export async function sendCopilotQuery(query: string, sessionId: string = 'default') {
    const token = localStorage.getItem('token');
    const response = await fetch(`${API_URL}/copilot/query`, {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${token}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({ query, session_id: sessionId })
    });
    if (!response.ok) throw new Error('Failed to send copilot query');
    return response.json();
}

export async function login(credentials: any) {
    const response = await fetch(`${API_URL}/auth/token`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify({
            email: credentials.email,
            password: credentials.password
        })
    });
    if (!response.ok) {
        const error = await response.json();
        const detail = typeof error.detail === 'string'
            ? error.detail
            : JSON.stringify(error.detail);
        throw new Error(detail || 'Operation failed');
    }
    return response.json();
}

export async function register(userData: any) {
    const response = await fetch(`${API_URL}/auth/register`, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(userData)
    });
    if (!response.ok) {
        const error = await response.json();
        throw new Error(error.detail || 'Registration failed');
    }
    return response.json();
}
